VALUES
  ('social-worker-moex-03600', 'social-worker', 'social-worker-moex-113-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關不同團體的敘述，下列何者正確？', '["社會服務組織的志工訓練也是一種教育性團體", "問題解決與決策團體並不會完成特定的任務與目標，所以它不是一種任務性團體", "自助團體通常是由有類似需求而期待自我改變的人所組成的", "會心團體由於具有親近人際互動與自我揭露的特質，因此主要的目標並非關注於人際覺察 的改善"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:20+00:00", "source_pdf_sha1": "5dcbcb793235", "answer_pdf_sha1": "5760c570da03", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "103", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03601', 'social-worker', 'social-worker-moex-113-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關生態系統觀點對於團體的觀點，下列敘述何者錯誤？', '["在規劃團體方案時，需考量團體所處社會文化的影響", "當團體工作面臨困境時，可以試著從個人、團體、組織、社區、社會任何一個系統介入， 以促發各系統的改變", "生態系統理論較不重視團體成員的性別、年齡等個別因素", "生態系統理論認為不同層次的系統都是團體賴以生存的生態圈，任何一個層次的系統出現 問題，都會影響團體的運作"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:20+00:00", "source_pdf_sha1": "5dcbcb793235", "answer_pdf_sha1": "5760c570da03", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "103", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03602', 'social-worker', 'social-worker-moex-113-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關社會團體工作的歷史發展，下列敘述何者正確？', '["於1884年在倫敦成立的湯恩比館（ToynbeeHall），工作者會運用傳教式與社區共同合作等 不同的策略", "珍亞當斯（JaneAddams）在芝加哥成立的赫爾館（HullHouse）主要處理社區各種活動， 尚未及於社會行動的參與", "社區睦鄰中心（settlementhouse）會以社會行動解決地方問題，並對社會政策與法令有所影響", "源自美國的基督教青年會（YMCA）在廣泛地於各地擴展之後，也推動了英國基督教青年 會的成立"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:20+00:00", "source_pdf_sha1": "5dcbcb793235", "answer_pdf_sha1": "5760c570da03", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "103", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03603', 'social-worker', 'social-worker-moex-113-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關開放性團體運用的考量因素，下列何者錯誤？', '["為穩定團體運作，可以將每次團體活動事先公告，並有結構性的操作團體活動", "團體工作者可依新成員的加入來調整團體活動", "讓成員自由進出團體，不需考量團體的持續性，一旦人數不足即可結束團體", "每次團體的主題最好是獨立的單元，方便團體成員不會因為未參與前次團體而無法融入"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:20+00:00", "source_pdf_sha1": "5dcbcb793235", "answer_pdf_sha1": "5760c570da03", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "103", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03604', 'social-worker', 'social-worker-moex-113-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '某機構想要規劃與辦理新住民家長支持團體，有關團體組成的必要考量因素，下列何者最正確？', '["成員必須是同一性別", "必須控制成員是否有參加團體經驗的因素", "必須考量成員的子女人數", "必須考量成員的族群及文化背景的影響"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:20+00:00", "source_pdf_sha1": "5dcbcb793235", "answer_pdf_sha1": "5760c570da03", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "103", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03605', 'social-worker', 'social-worker-moex-113-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關團體中的沉默，下列何者錯誤？', '["在團體開始階段的沉默主要和成員正在適應團體的運作有關", "團體工作者的引導語，若不夠明確或清楚，可能會造成成員無法理解而陷入沉默", "在團體中間階段，開始更深入的自我揭露和個人探索時，可能會引發成員的焦慮而出現沉默", "團體工作者可積極鼓勵沉默的成員發言或回應，負起促進成員間互動的責任"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:20+00:00", "source_pdf_sha1": "5dcbcb793235", "answer_pdf_sha1": "5760c570da03", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "103", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03606', 'social-worker', 'social-worker-moex-113-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關競爭團體和合作團體的敘述，下列何者正確？', '["足球隊是一個具高度合作氣氛的團體，會依據團體成員個人表現給予獎勵", "戲劇試演的團體晤談是具有競爭性的，能阻礙別人達成目標，自己才有可能完成自己的目 標〜加入戲劇團", "在問題解決的團體中，競爭會強化創造力、協調、分工與分享", "合作團體的正向特質會被一位新加入競爭性成員所強化"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:20+00:00", "source_pdf_sha1": "5dcbcb793235", "answer_pdf_sha1": "5760c570da03", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "103", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03607', 'social-worker', 'social-worker-moex-113-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '具創傷知情的團體工作目的在營造安全環境，與成員一起合作達成有意義的目標，下列作法 何者不適用於團體初期階段？', '["理解到早年經驗暴力攻擊的成員，對參與團體感到疑慮和警戒", "練習不同意見表達，適應團體差異性", "以正向積極方式鼓助成員分享，建立復原力特質", "辨識成員能力與處境、瞭解曾做的努力"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:20+00:00", "source_pdf_sha1": "5dcbcb793235", "answer_pdf_sha1": "5760c570da03", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "103", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03608', 'social-worker', 'social-worker-moex-113-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '協同領導要發揮功能，需要有周詳的考量與規劃。下列何者不是團體領導者與協同領導者合 作議題？', '["團體內容的責任分攤", "團體中出現強烈情緒可能採取的作法", "團體中的責任通報", "團體過程中不能超越的底線"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:20+00:00", "source_pdf_sha1": "5dcbcb793235", "answer_pdf_sha1": "5760c570da03", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "103", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03609', 'social-worker', 'social-worker-moex-113-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列何種情況最符合團體工作平等、不歧視的招募原則？', '["因場地限制，育兒指導團體以非身心障礙家庭為對象", "單親家長團體，以18歲以上男性或女性單親家長為對象", "年長者健康促進團體，以65歲以上男女，原住民族55歲以上男女為對象", "男性被害人支持團體，以遭受親密關係暴力之異性戀男性被害人為對象"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:20+00:00", "source_pdf_sha1": "5dcbcb793235", "answer_pdf_sha1": "5760c570da03", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "103", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
